export const getGetGameStatsUrl = () => {




  return `/api/game/stats`
}

/**
 * @summary Get game statistics
 */
export const getGameStats = async ( options?: RequestInit): Promise<GameStats> => {

  return customFetch<GameStats>(getGetGameStatsUrl(),
  {
    ...options,
    method: 'GET'


  }
);}





export const getGetGameStatsQueryKey = () => {
    return [
    `/api/game/stats`
    ] as const;
    }


export const getGetGameStatsQueryOptions = <TData = Awaited<ReturnType<typeof getGameStats>>, TError = ErrorType<unknown>>( options?: { query?:UseQueryOptions<Awaited<ReturnType<typeof getGameStats>>, TError, TData>, request?: SecondParameter<typeof customFetch>}
) => {

const {query: queryOptions, request: requestOptions} = options ?? {};

  const queryKey =  queryOptions?.queryKey ?? getGetGameStatsQueryKey();



    const queryFn: QueryFunction<Awaited<ReturnType<typeof getGameStats>>> = ({ signal }) => getGameStats({ signal, ...requestOptions });





   return  { queryKey, queryFn, ...queryOptions} as UseQueryOptions<Awaited<ReturnType<typeof getGameStats>>, TError, TData> & { queryKey: QueryKey }
}

export type GetGameStatsQueryResult = NonNullable<Awaited<ReturnType<typeof getGameStats>>>
export type GetGameStatsQueryError = ErrorType<unknown>


/**
 * @summary Get game statistics
 */

export function useGetGameStats<TData = Awaited<ReturnType<typeof getGameStats>>, TError = ErrorType<unknown>>(
  options?: { query?:UseQueryOptions<Awaited<ReturnType<typeof getGameStats>>, TError, TData>, request?: SecondParameter<typeof customFetch>}

 ):  UseQueryResult<TData, TError> & { queryKey: QueryKey } {

  const queryOptions = getGetGameStatsQueryOptions(options)

  const query = useQuery(queryOptions) as  UseQueryResult<TData, TError> & { queryKey: QueryKey };

  return { ...query, queryKey: queryOptions.queryKey };
}







